// Counts how many distinct elements within the sub-array [start, end]
// occur exactly as many times as their value.
int solveQuery(int start, int end, const vector<int>& arr) 
{
    unordered_map<int, int> frequency;
    // Build frequency map for the given range (inclusive)
    for (int i = start; i <= end && i < static_cast<int>(arr.size()); ++i) {
        ++frequency[arr[i]];
    }
    // Count elements whose value equals their frequency
    int count = 0;
    for (const auto& [value, freq] : frequency) {
        if (value == freq) {
            ++count;
        }
    }
    return count;
}

