// Returns the sum of all integer numbers present in the input string.
long long findSum(const std::string& str) {
    long long sum = 0;   // Accumulates the total sum
    long long num = 0;   // Builds the current number
    for (char ch : str) {
        if (std::isdigit(static_cast<unsigned char>(ch))) {
            // Extend the current number
            num = num * 10 + (ch - '0');
        } else {
            // Non-digit encountered: add current number to sum, reset num
            sum += num;
            num = 0;
        }
    }
    // Add the last number, if any
    return sum + num;
}
