// Returns index of the smallest element >= x in a sorted array.
// If such element doesn’t exist, returns -1.
int ceilSearch(const std::vector<int>& arr, int low, int high, int x)
{
    // If x is smaller than or equal to the first element
    if (x <= arr[low])
        return low;
    // If x is greater than the last element
    if (x > arr[high])
        return -1;
    int mid = (low + high) / 2;
    // If x is present at mid
    if (arr[mid] == x)
        return mid;
    // If x is greater than arr[mid]
    if (arr[mid] < x)
    {
        // Check if x is smaller than or equal to the next element
        if (mid + 1 <= high && x <= arr[mid + 1])
            return mid + 1;
        // Recur for the right half
        return ceilSearch(arr, mid + 1, high, x);
    }
    else  // arr[mid] > x
    {
        // Check if x is greater than the previous element
        if (mid - 1 >= low && x > arr[mid - 1])
            return mid;
        // Recur for the left half
        return ceilSearch(arr, low, mid - 1, x);
    }
}

