bool HalfDiagonalSums(const std::vector<std::vector<int>>& mat, int n)
{
    long long diag1_left  = 0;
    long long diag1_right = 0;
    long long diag2_left  = 0;
    long long diag2_right = 0;
    int i = 0;
    int j = n - 1;
    while (i < n)
    {
        if (i < n / 2)
        {
            diag1_left += mat[i][i];   // main-diagonal (upper half)
            diag2_left += mat[j][i];   // anti-diagonal (upper half)
        }
        else if (i > n / 2)
        {
            diag1_right += mat[i][i];  // main-diagonal (lower half)
            diag2_right += mat[j][i];  // anti-diagonal (lower half)
        }
        ++i;
        --j;
    }
    return (diag1_left  == diag2_right &&
            diag2_right == diag2_left &&
            diag1_right == diag2_left &&
            diag2_right == mat[n / 2][n / 2]);
}

