bool areConsecutive(const int arr[], int n)
{
    // An empty array (or negative length) cannot contain consecutive numbers
    if (n < 1)
        return false;
    // Find minimum and maximum elements in the array
    int Min = arr[0], Max = arr[0];
    for (int i = 1; i < n; ++i) {
        if (arr[i] < Min) Min = arr[i];
        if (arr[i] > Max) Max = arr[i];
    }
    // Check the basic property of consecutive integers
    if (Max - Min + 1 != n)
        return false;
    // Auxiliary structure to detect duplicates
    std::vector<bool> visited(n, false);
    for (int i = 0; i < n; ++i) {
        int idx = arr[i] - Min;   // map value to index 0..n-1
        if (visited[idx])         // seen before ⇒ duplicate
            return false;
        visited[idx] = true;
    }
    return true;  // All numbers are unique and within the required range
}

