// Returns true if the given array `pre` can represent 
// the preorder traversal of a Binary Search Tree (BST).
bool canRepresentBST(const vector<int>& pre, int n) {
    stack<int> s;
    int root = INT_MIN;               // Smallest possible value
    for (int i = 0; i < n; ++i) {
        // If we find a node that is on the left side 
        // but smaller than an allowed root, return false.
        if (pre[i] < root)
            return false;
        // Nodes popped here will become new roots for 
        // the upcoming right subtrees.
        while (!s.empty() && s.top() < pre[i]) {
            root = s.top();
            s.pop();
        }
        // Push current value to stack.
        s.push(pre[i]);
    }
    return true;
}

