/*
 * Detects whether multiplying two 64-bit signed integers overflows
 * the range representable by a signed 64-bit integer.
 *
 * The strategy mirrors the original Python code:
 *   1. Handle the trivial zero cases.
 *   2. Compute the product in a wider type (__int128) so the
 *      intermediate result cannot overflow.
 *   3. If a == (result / b) the multiplication was safe;
 *      otherwise, overflow occurred.
 *
 * NOTE:  __int128 is a GNU/Clang extension and is supported by
 *        almost all modern compilers targeting x86/ARM.  If it
 *        is unavailable on your platform, you’ll need a different
 *        overflow-detection strategy.
 */
bool isOverflow(long long a, long long b)
{
    // Step 1: quick exit for zeros
    if (a == 0 || b == 0)
        return false;
    // Step 2: do the multiplication in a 128-bit integer
    __int128 product = static_cast<__int128>(a) * static_cast<__int128>(b);
    // Step 3: verify the result
    return a != static_cast<long long>(product / b);
}

