// Returns true if the (possibly very large) non-negative integer
// given as a string is divisible by 13, otherwise returns false.
bool checkDivisibility(std::string num)
{
    int length = static_cast<int>(num.size());
    // Special case : 0 is divisible by any non–zero number.
    if (length == 1 && num[0] == '0')
        return true;
    // Pad with zeroes on the right so the length becomes a multiple of 3.
    if (length % 3 == 1) {
        num += "00";
        length += 2;
    } else if (length % 3 == 2) {
        num += '0';
        length += 1;
    }
    long long sum = 0;   // can be negative while accumulating
    int sign = 1;        // alternates between +1 and -1
    // Process the number in groups of three digits, starting from the right.
    for (int i = length - 1; i >= 2; i -= 3) {
        int units     =  num[i]     - '0';
        int tens      = (num[i - 1] - '0') * 10;
        int hundreds  = (num[i - 2] - '0') * 100;
        int group = hundreds + tens + units;
        sum += group * sign;
        sign = -sign;   // alternate the sign
    }
    sum = std::abs(sum);
    return (sum % 13 == 0);
}

