// Returns true if str1 can be obtained by rotating str2 by
// exactly two positions (either clockwise or anti-clockwise).
bool isRotated(const std::string& str1, const std::string& str2)
{
    // If lengths differ, rotation is impossible.
    if (str1.length() != str2.length())
        return false;
    const std::size_t len = str2.length();
    // Anti-clockwise rotation by two positions
    std::string anticlock_rot = str2.substr(len - 2) + str2.substr(0, len - 2);
    // Clockwise rotation by two positions
    std::string clock_rot = str2.substr(2) + str2.substr(0, 2);
    // Check if either rotation matches str1
    return (str1 == clock_rot) || (str1 == anticlock_rot);
}
