bool isPossible(int n, int index, int modulo, int M,
                const std::vector<int>& arr, std::vector<std::vector<int>>& dp)
{
    // Ensure modulo is always in the range [0, M-1]
    modulo = ((modulo % M) + M) % M;
    // Base case: all elements have been considered
    if (index == n) {
        return (modulo == 0);
    }
    // Return cached result if already computed
    if (dp[index][modulo] != -1) {
        return static_cast<bool>(dp[index][modulo]);
    }
    // Try adding the current element
    bool placeAdd = isPossible(n, index + 1, modulo + arr[index], M, arr, dp);
    // Try subtracting the current element
    bool placeMinus = isPossible(n, index + 1, modulo - arr[index], M, arr, dp);
    // Result for current state
    bool res = placeAdd || placeMinus;
    // Memoize and return
    dp[index][modulo] = static_cast<int>(res);
    return res;
}

