void spiralFill(int m, int n, std::vector<std::vector<int>>& a)
{
    int val = 1;
    int k = 0, l = 0;          // k -> starting row index, l -> starting column index
    while (k < m && l < n)
    {
        // Fill the top row from the remaining rows
        for (int i = l; i < n; ++i)
            a[k][i] = val++;
        ++k;                   // Move down to the next row
        // Fill the rightmost column from the remaining columns
        for (int i = k; i < m; ++i)
            a[i][n - 1] = val++;
        --n;                   // Move left to the previous column
        // Fill the bottom row if any rows remain
        if (k < m)
        {
            for (int i = n - 1; i >= l; --i)
                a[m - 1][i] = val++;
            --m;               // Move up to the previous row
        }
        // Fill the leftmost column if any columns remain
        if (l < n)
        {
            for (int i = m - 1; i >= k; --i)
                a[i][l] = val++;
            ++l;               // Move right to the next column
        }
    }
}

