/*
 * Convert a decimal number to its binary representation.
 *   num     : the (positive) decimal number to convert
 *   k_prec  : the number of bits to generate after the binary point
 */
std::string decimalToBinary(double num, int k_prec)
{
    std::string binary;
    // Extract integral part
    long long integral = static_cast<long long>(num);
    double fractional  = num - integral;
    /* -------- integral part -------- */
    if (integral == 0)
    {
        binary += '0';
    }
    else
    {
        while (integral > 0)
        {
            int rem = integral % 2;
            binary.push_back(static_cast<char>('0' + rem));
            integral /= 2;
        }
        std::reverse(binary.begin(), binary.end());
    }
    binary.push_back('.');
    /* -------- fractional part -------- */
    while (k_prec-- > 0)
    {
        // multiply fractional part by 2
        fractional *= 2;
        int fract_bit = static_cast<int>(fractional);
        if (fract_bit == 1)
        {
            fractional -= fract_bit;
            binary.push_back('1');
        }
        else
        {
            binary.push_back('0');
        }
    }
    return binary;
}
