long long findSubsequenceCount(const std::string& S, const std::string& T) {
    int m = static_cast<int>(T.size());
    int n = static_cast<int>(S.size());
    if (m > n) return 0;
    // DP table where mat[i][j] stores the number of ways
    // T[0..i-1] appears as a subsequence in S[0..j-1]
    std::vector<std::vector<long long>> mat(m + 1, std::vector<long long>(n + 1, 0));
    // An empty T (length 0) is a subsequence of any prefix of S
    for (int j = 0; j <= n; ++j)
        mat[0][j] = 1;
    // Fill the DP table
    for (int i = 1; i <= m; ++i) {
        for (int j = 1; j <= n; ++j) {
            if (T[i - 1] != S[j - 1]) {
                mat[i][j] = mat[i][j - 1];  // Current chars don't match
