int countDecodingDP(const std::string& digits, int n)
{
    // Edge-case: empty string
    if (n == 0) return 0;
    // `count[i]` will store the number of ways to decode
    // the substring `digits[0..i-1]`
    std::vector<int> count(n + 1, 0);
    count[0] = 1;  // An empty string has one valid decoding
    count[1] = 1;  // A single non-zero character has one decoding
    // If the very first character is '0', there is no valid decoding
