/*
 * Returns the total number of set bits in the binary
 * representation of every integer from 0 to n (inclusive).
 */
long long countSetBits(long long n)
{
    long long ans = 0;
    int i = 0;
    // Iterate over every bit position
    while ((1LL << i) <= n)
    {
        int k = 0;                     // toggles between 0 and 1
        long long change = 1LL << i;   // length of a block at this bit level
        // Traverse all numbers from 0 to n
        for (long long j = 0; j <= n; ++j)
        {
            ans += k;                  // add contribution of current bit
            if (change == 1)
            {
                k = !k;                // toggle k when a block ends
                change = 1LL << i;     // reset block length counter
            }
            else
            {
                --change;              // move towards end of the current block
            }
        }
        ++i;                           // move to the next bit position
    }
    return ans;
}

