string decode(const string& Str) {
    vector<int>    integerstack;   // stack for integers
    vector<char>   stringstack;    // stack for characters (includes '[')
    string temp   = "";
    string result = "";
    for (size_t i = 0; i < Str.length(); ++i) {
        int count = 0;
        /* -------------  When the current character is a digit ------------- */
        if (isdigit(Str[i])) {
            while (i < Str.length() && isdigit(Str[i])) {
                count = count * 10 + (Str[i] - '0');
                ++i;
            }
            --i;                       // compensate for the for-loop ++i
            integerstack.push_back(count);
        }
        /* ------------------------- Closing bracket ------------------------ */
        else if (Str[i] == ']') {
            temp  = "";
            count = 0;
            if (!integerstack.empty()) {
                count = integerstack.back();
                integerstack.pop_back();
            }
            // collect the encoded substring
            while (!stringstack.empty() && stringstack.back() != '[') {
                temp = stringstack.back() + temp;
                stringstack.pop_back();
            }
            // pop the opening '['
            if (!stringstack.empty() && stringstack.back() == '[')
                stringstack.pop_back();
            // repeat the collected substring 'count' times
            result.clear();
            for (int j = 0; j < count; ++j)
                result += temp;
            // push the expanded substring back onto the character stack
            for (char ch : result)
                stringstack.push_back(ch);
            result.clear();
        }
        /* -------------------------- Opening bracket ----------------------- */
        else if (Str[i] == '[') {
            if (i > 0 && isdigit(Str[i - 1])) {
                // '[' directly follows a number
                stringstack.push_back(Str[i]);
            } else {
                // implicit count == 1
                stringstack.push_back(Str[i]);
                integerstack.push_back(1);
            }
        }
        /* --------------------------- Alphabet ----------------------------- */
        else {
            stringstack.push_back(Str[i]);
        }
    }
    // assemble the final decoded string
    result.clear();
    while (!stringstack.empty()) {
        result = stringstack.back() + result;
        stringstack.pop_back();
    }
    return result;
}

