// Delannoy number D(m, n)
long long dealnnoy(int n, int m)
{
    // dp[i][j] will hold D(i, j)
    std::vector<std::vector<long long>> dp(m + 1, std::vector<long long>(n + 1, 0));
    // First row
    for (int j = 0; j <= m && j <= n; ++j)   // safeguard in case m > n
        dp[0][j] = 1;
    // First column
    for (int i = 0; i <= m; ++i)
        dp[i][0] = 1;
    // Fill the table
    for (int i = 1; i <= m; ++i)
        for (int j = 1; j <= n; ++j)
            dp[i][j] = dp[i - 1][j] + dp[i - 1][j - 1] + dp[i][j - 1];
    return dp[m][n];
}

