{
    // Calculate n = ⌈√m⌉
    long long n = static_cast<long long>(std::sqrt(static_cast<long double>(m)) + 1);
    // Compute a^n (mod m)
    long long an = 1;
    for (long long i = 0; i < n; ++i)
        an = (an * a) % m;
    // Baby-step: store values of (a^n)^i  (mod m)
    std::vector<long long> value(m, 0);
    long long cur = an;
    for (long long i = 1; i <= n; ++i) {
        if (value[cur] == 0)          // store the first occurrence only
            value[cur] = i;
        cur = (cur * an) % m;
    }
    // Giant-step: search for match
    cur = b;
    for (long long i = 0; i <= n; ++i) {
        if (value[cur] > 0) {
            long long ans = value[cur] * n - i;
            if (ans < m)
                return ans;           // discrete logarithm found
