std::string longDivision(const std::string& number, int divisor) {
    std::string ans;
    std::size_t idx = 0;
    // Current value under consideration
    int temp = number[idx] - '0';
    // Bring down digits until the current value is at least the divisor
    while (temp < divisor && idx + 1 < number.size()) {
        temp = temp * 10 + (number[++idx] - '0');
    }
    // Perform the division digit by digit
    while (idx < number.size()) {
        // Append the current quotient digit
        ans += static_cast<char>((temp / divisor) + '0');
        // Update the remainder
        temp = temp % divisor;
        ++idx;
        // Bring down the next digit, if any
        if (idx < number.size()) {
            temp = temp * 10 + (number[idx] - '0');
        }
    }
    // If the result is empty, the quotient is zero
    if (ans.empty()) {
        return "0";
    }
    return ans;
}

