int lps(const std::string& seq)
{
    int n = static_cast<int>(seq.size());
    if (n == 0) return 0;
    // L[i][j] will hold the length of the LPS in seq[i..j]
    std::vector<std::vector<int>> L(n, std::vector<int>(n, 0));
    // Subsequences of length 1 are palindromes of length 1
    for (int i = 0; i < n; ++i)
        L[i][i] = 1;
    // Build the table. cl is the length of substring.
    for (int cl = 2; cl <= n; ++cl) {
        for (int i = 0; i <= n - cl; ++i) {
