int minPalPartion(const string& str) {
    int n = static_cast<int>(str.length());
    if (n == 0) return 0;
    // C[i][j] will hold the minimum number of cuts required
    // for the substring str[i..j].
    vector<vector<int>> C(n, vector<int>(n, 0));
    // P[i][j] will be true if str[i..j] is a palindrome.
    vector<vector<bool>> P(n, vector<bool>(n, false));
    // Every single character is a palindrome of length 1.
    for (int i = 0; i < n; ++i) {
        P[i][i] = true;
        C[i][i] = 0;  // Zero cuts needed for a single character.
    }
    // L is the substring length
    for (int L = 2; L <= n; ++L) {
        for (int i = 0; i <= n - L; ++i) {
            int j = i + L - 1;
            if (L == 2) {
                P[i][j] = (str[i] == str[j]);
            } else {
                P[i][j] = (str[i] == str[j]) && P[i + 1][j - 1];
            }
            if (P[i][j]) {
                C[i][j] = 0; // No cut needed if substring is already a palindrome
            } else {
                const int INF = 1e9;
                C[i][j] = INF;
                for (int k = i; k < j; ++k) {
                    C[i][j] = min(C[i][j], C[i][k] + C[k + 1][j] + 1);
                }
            }
        }
    }
    return C[0][n - 1];
}

