// Recursive function that returns the minimum number of insertions
// needed to convert the substring str[l..h] into a palindrome.
int findMinInsertions(const std::string& str, int l, int h)
{
    if (l > h)
        return INT_MAX;                         // Equivalent to Python's sys.maxsize
    if (l == h)
        return 0;                               // Single character is already a palindrome
    if (l == h - 1)
        return (str[l] == str[h]) ? 0 : 1;      // Two-character substring
    if (str[l] == str[h])
        return findMinInsertions(str, l + 1, h - 1); // Characters match, shrink both ends
    else
        return 1 + std::min(findMinInsertions(str, l,     h - 1),   // Insert at right end
                            findMinInsertions(str, l + 1, h));      // Insert at left end
}

