// Count the number of ways to parenthesize a boolean expression so that it
// evaluates to TRUE.
//   symb  : string with symbols 'T' (true) or 'F' (false)  – length = n
//   oper  : string with operators '&', '|', '^'            – length = n-1
//   return: number of possible parenthesizations that evaluate to TRUE
long long countParenth(const std::string& symb, const std::string& oper)
{
    const int n = static_cast<int>(symb.size());
    if (n == 0) return 0;
    // T[i][j] – #ways sub-expression (i..j) is true
    // F[i][j] – #ways sub-expression (i..j) is false
    std::vector<std::vector<long long>> T(n, std::vector<long long>(n, 0));
    std::vector<std::vector<long long>> F(n, std::vector<long long>(n, 0));
    // Base cases: single symbols
    for (int i = 0; i < n; ++i)
    {
        if (symb[i] == 'T') T[i][i] = 1;
        else                 T[i][i] = 0;
        if (symb[i] == 'F') F[i][i] = 1;
        else                 F[i][i] = 0;
    }
    // gap is current sub-expression length minus 1
    for (int gap = 1; gap < n; ++gap)
    {
        for (int i = 0, j = gap; j < n; ++i, ++j)
        {
            T[i][j] = F[i][j] = 0;                // reset counters
            for (int g = 0; g < gap; ++g)
            {
                int k   = i + g;                  // operator position
                long long tik = T[i][k] + F[i][k];
                long long tkj = T[k + 1][j] + F[k + 1][j];
                switch (oper[k])
                {
                    case '&':
                        T[i][j] += T[i][k] * T[k + 1][j];
                        F[i][j] += (tik * tkj - T[i][k] * T[k + 1][j]);
                        break;
                    case '|':
                        F[i][j] += F[i][k] * F[k + 1][j];
                        T[i][j] += (tik * tkj - F[i][k] * F[k + 1][j]);
                        break;
                    case '^':
                        T[i][j] += (F[i][k] * T[k + 1][j] +
                                    T[i][k] * F[k + 1][j]);
                        F[i][j] += (T[i][k] * T[k + 1][j] +
                                    F[i][k] * F[k + 1][j]);
                        break;
                }
            }
        }
    }
    return T[0][n - 1];
}

