// Function to compute the length of the Longest Increasing Subsequence
int lis(const std::vector<int>& arr) {
    int n = static_cast<int>(arr.size());
    if (n == 0) return 0;
    std::vector<int> lis(n, 1);
    for (int i = 1; i < n; ++i) {
        for (int j = 0; j < i; ++j) {
            if (arr[i] > arr[j] && lis[i] < lis[j] + 1) {
                lis[i] = lis[j] + 1;
            }
        }
    }
    int maximum = 0;
    for (int i = 0; i < n; ++i) {
        maximum = std::max(maximum, lis[i]);
    }
    return maximum;
}
