// Returns true if there is a subset of `set[0..n-1]` with sum equal to `sum`
bool isSubsetSum(const std::vector<int>& set, int n, int sum)
{
    /* `subset[i][j]` will be true if there exists a subset of the first `i`
       elements that has a sum equal to `j`. */
    std::vector<std::vector<bool>> subset(n + 1, std::vector<bool>(sum + 1, false));
    // If sum is 0, answer is true for any `i`
    for (int i = 0; i <= n; ++i)
        subset[i][0] = true;
    // If i == 0 and sum > 0, answer is false (already defaulted to false)
    // Fill the subset table in bottom-up manner
    for (int i = 1; i <= n; ++i)
    {
        for (int j = 1; j <= sum; ++j)
        {
            if (j < set[i - 1])
                subset[i][j] = subset[i - 1][j];
            else  // j >= set[i - 1]
                subset[i][j] = subset[i - 1][j] || subset[i - 1][j - set[i - 1]];
        }
    }
    return subset[n][sum];
}

