// Returns the equilibrium index of the array, or -1 if none exists.
int equilibrium(const std::vector<int>& arr)
{
    long long total_sum = std::accumulate(arr.begin(), arr.end(), 0LL);
    long long left_sum  = 0;
    for (std::size_t i = 0; i < arr.size(); ++i) {
        total_sum -= arr[i];         // total_sum now holds the right-side sum
        if (left_sum == total_sum)   // equilibrium condition
            return static_cast<int>(i);
        left_sum += arr[i];          // update left-side sum for next iteration
    }
    return -1;                       // no equilibrium index found
}

