bool findDuplicateParenthesis(const std::string& str) {
    std::stack<char> st;
    for (char ch : str) {
        if (ch == ')') {
            if (st.empty())        // safety check (unbalanced expression)
                return false;
            char top = st.top();
            st.pop();
            int elementsInside = 0;
            while (!st.empty() && top != '(') {
                ++elementsInside;
                top = st.top();
                st.pop();
            }
            // If there were no characters inside the current pair of
            // parentheses, we found duplicate (redundant) parentheses.
            if (elementsInside < 1)
                return true;
        } else {
            st.push(ch);
        }
    }
    return false;
}
