long long maxPrimeFactors(long long n) {
    long long maxPrime = -1;
    // Divide n by 2 until it becomes odd
    while (n % 2 == 0) {
        maxPrime = 2;
        n >>= 1;           // equivalent to n /= 2
    }
    // n is now odd. Test odd divisors up to √n
    for (long long i = 3; i <= static_cast<long long>(std::sqrt(n)); i += 2) {
        while (n % i == 0) {
            maxPrime = i;
            n /= i;
        }
    }
    // If n is a prime number greater than 2, it is the largest prime factor
    if (n > 2)
        maxPrime = n;
    return maxPrime;
}

