long long MaxDotProduct(const std::vector<long long>& A,
                        const std::vector<long long>& B,
                        int m, int n)
{
    // dp[i][j] = best value using first i elements of B
    //            and first j elements of A
    std::vector<std::vector<long long>> dp(n + 1,
                                           std::vector<long long>(m + 1, 0));
