// Returns the maximum possible product of any three numbers in the array.
// If the array contains fewer than three elements, the function returns -1.
long long maxProduct(vector<long long>& arr) {
    int n = static_cast<int>(arr.size());
    if (n < 3) {
        return -1;                 // Not enough elements
    }
    sort(arr.begin(), arr.end());
    // Option 1: product of two smallest (possibly negative) and the largest element
    long long option1 = arr[0] * arr[1] * arr[n - 1];
    // Option 2: product of the three largest elements
    long long option2 = arr[n - 1] * arr[n - 2] * arr[n - 3];
    return max(option1, option2);
}

