// Returns the maximum possible equal sum of the three stacks
int maxSum(const std::vector<int>& stack1,
           const std::vector<int>& stack2,
           const std::vector<int>& stack3,
           int n1, int n2, int n3)
{
    // Compute the initial sums of the three stacks
    int sum1 = std::accumulate(stack1.begin(), stack1.end(), 0);
    int sum2 = std::accumulate(stack2.begin(), stack2.end(), 0);
    int sum3 = std::accumulate(stack3.begin(), stack3.end(), 0);
    // Indices representing the current "top" of each stack
    int top1 = 0, top2 = 0, top3 = 0;
    while (true) {
        // If any stack is exhausted, equal sum cannot be achieved
        if (top1 == n1 || top2 == n2 || top3 == n3)
            return 0;
        // If all sums are equal, we've found the answer
        if (sum1 == sum2 && sum2 == sum3)
            return sum1;
        // Remove the top element from the stack with the largest sum
        if (sum1 >= sum2 && sum1 >= sum3) {
            sum1 -= stack1[top1++];
        } else if (sum2 >= sum1 && sum2 >= sum3) {
            sum2 -= stack2[top2++];
        } else {  // sum3 is the largest (or tied)
            sum3 -= stack3[top3++];
        }
    }
}

