/*
 * Returns median of a row-wise sorted matrix `m`
 * having `r` rows and `c` columns.
 */
int binaryMedian(const vector<vector<int>>& m, int r, int c)
{
    int mi = INT_MAX;      // smallest element among first column values
    int mx = INT_MIN;      // largest  element among last  column values
    for (int i = 0; i < r; ++i) {
        mi = min(mi, m[i][0]);       // first element of the i-th row
        mx = max(mx, m[i][c - 1]);   // last  element of the i-th row
    }
    const int desired = (r * c + 1) / 2;   // position of the median
    while (mi < mx) {
        int mid   = mi + (mx - mi) / 2;
        int place = 0;                     // how many numbers ≤ mid
        for (int i = 0; i < r; ++i) {
            // upper_bound returns iterator to first element > mid
            place += upper_bound(m[i].begin(), m[i].end(), mid) - m[i].begin();
        }
        if (place < desired)
            mi = mid + 1;   // median is greater than `mid`
        else
            mx = mid;       // median is ≤ `mid`
    }
    cout << "Median is " << mi << '\n';
    return mi;
}
