// Returns the smallest number that needs to be multiplied with `n` 
// so that the product becomes a perfect square.
long long findMinNumber(long long n) {
    long long ans   = 1;
    long long count = 0;
    // Handle factor 2 separately
    while (n % 2 == 0) {
        ++count;
        n /= 2;
    }
    if (count % 2 != 0) {
        ans *= 2;
    }
    // Handle odd factors from 3 onwards
    for (long long i = 3; i * i <= n; i += 2) {
        count = 0;
        while (n % i == 0) {
            ++count;
            n /= i;
        }
        if (count % 2 != 0) {
            ans *= i;
        }
    }
    // If n is still > 2, then it is prime and its exponent is 1 (odd)
    if (n > 2) {
        ans *= n;
    }
    return ans;
}

