int minCoins(const std::vector<int>& coins, int m, int V) {
    // Create a table to store results of subproblems
    std::vector<int> table(V + 1, INT_MAX);
    // Base case (If given value is 0)
    table[0] = 0;
    // Compute minimum coins required for all values from 1 to V
    for (int i = 1; i <= V; ++i) {
        // Go through all coins smaller than or equal to i
        for (int j = 0; j < m; ++j) {
            if (coins[j] <= i) {
                int sub_res = table[i - coins[j]];
                if (sub_res != INT_MAX && sub_res + 1 < table[i]) {
                    table[i] = sub_res + 1;
                }
            }
        }
    }
    return table[V];
}
