// Computes the mirror image of the point (x1, y1) with respect to the line
// a*x + b*y + c = 0. The result is returned as a std::pair<double, double> 
// where first = x-coordinate and second = y-coordinate of the reflected point.
std::pair<double, double> mirrorImage(double a, double b, double c,
                                      double x1, double y1)
{
    // Factor used to project the point onto the line and reflect it
    double temp = -2.0 * (a * x1 + b * y1 + c) / (a * a + b * b);
    // Coordinates of the mirrored point
    double x = temp * a + x1;
    double y = temp * b + y1;
    return {x, y};
}

