int countEndless(const std::vector<std::vector<int>>& input, int n)
{
    // Auxiliary matrices that store whether the "endless" condition
    // holds when scanning from the right (row) or from the bottom (col)
    std::vector<std::vector<int>> row(n, std::vector<int>(n, 0));
    std::vector<std::vector<int>> col(n, std::vector<int>(n, 0));
    /* 1) Fill `col`:
          For every column j, traverse upward (i = n-1 .. 0).
          isEndless becomes 0 as soon as a 0 is encountered.
          col[i][j] == 1  ⇔  all cells from (i,j) down to (n-1,j) are 1-s.
    */
    for (int j = 0; j < n; ++j) {
        int isEndless = 1;
        for (int i = n - 1; i >= 0; --i) {
            if (input[i][j] == 0)
                isEndless = 0;
            col[i][j] = isEndless;
        }
    }
    /* 2) Fill `row`:
          For every row i, traverse right-to-left (j = n-1 .. 0).
          isEndless becomes 0 as soon as a 0 is encountered.
          row[i][j] == 1  ⇔  all cells from (i,j) rightwards to (i,n-1) are 1-s.
    */
    for (int i = 0; i < n; ++i) {
        int isEndless = 1;
        for (int j = n - 1; j >= 0; --j) {
            if (input[i][j] == 0)
                isEndless = 0;
            row[i][j] = isEndless;
        }
    }
    /* 3) Count positions (i, j) where both conditions hold.
          Note the Python code starts j from 1, reproducing that here.
    */
    int ans = 0;
    for (int i = 0; i < n; ++i) {
        for (int j = 1; j < n; ++j) {
            if (row[i][j] && col[i][j])
                ++ans;
        }
    }
    return ans;
}

