// Counts the number of times string `b` appears as a subsequence in string `a`
long long countSubsequences(const std::string& a, const std::string& b) {
    std::size_t m = a.size();
    std::size_t n = b.size();
    // lookup[i][j] will store the answer for prefixes a[0..i-1], b[0..j-1]
    std::vector<std::vector<long long>> lookup(m + 1, std::vector<long long>(n + 1, 0));
    // Initialize first row: when a's length is 0, b can't be matched except for empty subsequence
    for (std::size_t j = 0; j <= n; ++j)
        lookup[0][j] = 0;
    // Initialize first column: empty string b is a subsequence of any prefix of a
    for (std::size_t i = 0; i <= m; ++i)
        lookup[i][0] = 1;
    // Fill the table bottom-up
    for (std::size_t i = 1; i <= m; ++i) {
        for (std::size_t j = 1; j <= n; ++j) {
            if (a[i - 1] == b[j - 1])
                // Match found: add ways with and without current char of a
                lookup[i][j] = lookup[i - 1][j - 1] + lookup[i - 1][j];
            else
                // No match: skip current char of a
                lookup[i][j] = lookup[i - 1][j];
        }
    }
    return lookup[m][n];
}
