long long findSDSFunc(long long n)
{
    // Create a DP array of size n + 1 and initialize all values to 0
    std::vector<long long> DP(n + 1, 0);
    // Base cases
    if (n >= 1) DP[1] = 1;
    // Fill the DP array from 2 to n
    for (long long i = 2; i <= n; ++i)
    {
        if (i % 2 == 0)
        {
            // If i is even
            DP[i] = DP[i / 2];
        }
        else
        {
            // If i is odd
            DP[i] = DP[(i - 1) / 2] + DP[(i + 1) / 2];
        }
    }
    // Return the nth value in the DP table
    return DP[n];
}
