    Returns the largest possible GCD of any pair of elements in `arr`.
*/
int findMaxGCD(const vector<int>& arr)
{
    int n = static_cast<int>(arr.size());
    /* 1) Find the maximum element (`high`) in the array */
    int high = 0;
    for (int val : arr)
        high = max(high, val);
    /* 2) `divisors[i]` will count how many array elements are divisible by `i` */
    vector<int> divisors(high + 1, 0);
    /* 3) For every number, enumerate its divisors and update the counts */
    for (int num : arr)
    {
        for (int j = 1; 1LL * j * j <= num; ++j)
        {
            if (num % j == 0)
            {
                ++divisors[j];
                int other = num / j;
                if (other != j)          // avoid double-counting a square root divisor
                    ++divisors[other];
            }
        }
    }
    /* 4) Scan from `high` downwards to find the largest divisor
          that appears in at least two numbers */
    for (int i = high; i >= 1; --i)
        if (divisors[i] > 1)
            return i;
    return 1;   // If no GCD > 1 exists
}
