// Returns true if there exists a (non-empty) subsequence of `s`
// whose decimal value is divisible by 8.
bool isSubSeqDivisible(const std::string &s) {
    int n = static_cast<int>(s.size());
    // dp[i][r] == 1  ⇒ some subsequence using the first i digits
    //                  has remainder r when divided by 8.
    // (Extra two columns are harmless; only indices 0-7 are used.)
    std::vector<std::vector<int>> dp(n + 1, std::vector<int>(10, 0));
    // Convenience: store digits as integers, 1-based like in the Python code
    std::vector<int> arr(n + 1, 0);
    for (int i = 1; i <= n; ++i)
        arr[i] = s[i - 1] - '0';
    for (int i = 1; i <= n; ++i) {
        // A subsequence consisting solely of the current digit
        dp[i][arr[i] % 8] = 1;
        for (int j = 0; j < 8; ++j) {
            // Option 1: append current digit to a subsequence that gave remainder j
            int nxt = (j * 10 + arr[i]) % 8;
            if (dp[i - 1][j] > dp[i][nxt])
                dp[i][nxt] = dp[i - 1][j];
            // Option 2: skip current digit
            if (dp[i - 1][j] > dp[i][j])
                dp[i][j] = dp[i - 1][j];
        }
    }
    // Check if any prefix allows a subsequence divisible by 8
    for (int i = 1; i <= n; ++i)
        if (dp[i][0] == 1)
            return true;
    return false;
}

