// m       : total distance (last possible position)
// x       : positions of the billboards (size n, sorted, 1-based miles)
// revenue : revenue for each billboard position (size n)
// n       : number of possible billboard positions
// t       : required minimum distance between two billboards
//
// Returns the maximum obtainable revenue.
int maxRevenue(int m,
               const std::vector<int>& x,
               const std::vector<int>& revenue,
               int n,
               int t)
{
    std::vector<int> maxRev(m + 1, 0);   // maxRev[i] = best revenue up to mile i
    int nxtbb = 0;                       // index of next billboard candidate in x / revenue
    for (int i = 1; i <= m; ++i) {
        if (nxtbb < n) {
            if (x[nxtbb] != i) {
                // No billboard option at mile i
                maxRev[i] = maxRev[i - 1];
            } else {
                // There is a billboard candidate at mile i
                if (i <= t) {
                    // Not enough distance for a previous billboard
                    maxRev[i] = std::max(maxRev[i - 1], revenue[nxtbb]);
                } else {
                    // Either place billboard here (skip back t + 1 miles) or not
                    maxRev[i] = std::max(maxRev[i - t - 1] + revenue[nxtbb],
                                         maxRev[i - 1]);
                }
                ++nxtbb;  // move to next billboard candidate
            }
        } else {
            // All billboard positions processed
            maxRev[i] = maxRev[i - 1];
        }
    }
    return maxRev[m];
}

