// Returns the k-th largest sub-array sum
long long kthLargestSum(const vector<long long>& arr, int k)
{
    int n = static_cast<int>(arr.size());
    // prefix[i] holds sum of first i elements (1-based for convenience)
    vector<long long> prefix(n + 1, 0);
    for (int i = 1; i <= n; ++i)
        prefix[i] = prefix[i - 1] + arr[i - 1];
    // Min-heap that stores the k largest sums encountered so far
    priority_queue<long long, vector<long long>, greater<long long>> pq;
    for (int i = 1; i <= n; ++i)
    {
        for (int j = i; j <= n; ++j)
        {
            long long currentSum = prefix[j] - prefix[i - 1];
            if (static_cast<int>(pq.size()) < k)
            {
                pq.push(currentSum);
            }
            else if (pq.top() < currentSum)
            {
                pq.pop();
                pq.push(currentSum);
            }
        }
    }
    return pq.top();   // k-th largest sum
}
