// common segments (contiguous substrings) of length at least k.
int longestSubsequenceCommonSegment(int k, const std::string& s1, const std::string& s2)
{
    int n = static_cast<int>(s1.size());
    int m = static_cast<int>(s2.size());
    // lcs[i][j] : answer for prefixes s1[0..i-1], s2[0..j-1]
    std::vector<std::vector<int>> lcs(n + 1, std::vector<int>(m + 1, 0));
    // cnt[i][j] : length of the current equal suffix ending at s1[i-1], s2[j-1]
    std::vector<std::vector<int>> cnt(n + 1, std::vector<int>(m + 1, 0));
    for (int i = 1; i <= n; ++i) {
        for (int j = 1; j <= m; ++j) {
            // Standard LCS transition (skip one character from either string)
            lcs[i][j] = std::max(lcs[i - 1][j], lcs[i][j - 1]);
            // If current characters match, extend the equal-suffix counter
            if (s1[i - 1] == s2[j - 1]) {
                cnt[i][j] = cnt[i - 1][j - 1] + 1;
            } else {
                cnt[i][j] = 0;  // reset when characters differ
            }
            // If we have a common segment of length at least k, try using it
            if (cnt[i][j] >= k) {
                for (int a = k; a <= cnt[i][j]; ++a) {
                    lcs[i][j] = std::max(lcs[i][j], lcs[i - a][j - a] + a);
                }
            }
        }
    }
    return lcs[n][m];
}

