// Returns the maximum length of a correct (balanced) parenthesis subsequence
// in the whole string `s` (of size `n`).  Exactly replicates the logic of the
// given Python implementation.
int maxLength(const std::string& s, int n)
{
    // dp[i][j] will store the answer for the substring s[i … j]
    std::vector<std::vector<int>> dp(n, std::vector<int>(n, 0));
    // Base-case: substrings of length 2
    for (int i = 0; i + 1 < n; ++i)
        if (s[i] == '(' && s[i + 1] == ')')
            dp[i][i + 1] = 2;
    // Consider all substring lengths ≥ 3
    for (int l = 2; l < n; ++l)          // `l` is the distance between i and j
    {
        int i = -1;
        for (int j = l; j < n; ++j)
        {
            ++i;                         // now i == j - l
            // Case 1: pair the two ends if they form a bracket pair
            if (s[i] == '(' && s[j] == ')')
                dp[i][j] = 2 + dp[i + 1][j - 1];
            // Case 2: split the interval into two parts and take the best
            for (int k = i; k < j; ++k)
                dp[i][j] = std::max(dp[i][j], dp[i][k] + dp[k + 1][j]);
        }
    }
    return dp[0][n - 1];
}

