// Computes the n-th Leonardo number.
// L(0) = 1, L(1) = 1, L(n) = L(n-1) + L(n-2) + 1  for n ≥ 2
long long leonardo(int n) {
    std::vector<long long> dp;
    dp.reserve(n + 1);
    dp.push_back(1);          // L(0)
    if (n == 0) return 1;
    dp.push_back(1);          // L(1)
    for (int i = 2; i <= n; ++i) {
        dp.push_back(dp[i - 1] + dp[i - 2] + 1);
    }
    return dp[n];
}

