// Function to minimize the array using at most k adjacent swaps
void minimizeWithKSwaps(std::vector<int>& arr, int k)
{
    int n = static_cast<int>(arr.size());
    for (int i = 0; i < n - 1 && k > 0; ++i)          // iterate over each position
    {
        int pos = i;
        // find the smallest element within the next k positions
        for (int j = i + 1; j < n; ++j)
        {
            if (j - i > k)                            // no more than k swaps ahead
                break;
            if (arr[j] < arr[pos])
                pos = j;
        }
        // bring the smallest element found to index i using adjacent swaps
        for (int j = pos; j > i; --j)
            std::swap(arr[j], arr[j - 1]);
        k -= (pos - i);                               // reduce remaining swaps
    }
}

