/*  Returns the longest repeated subsequence of the given string.
 *  (A subsequence that appears at least twice in the string,  
 *   and the two occurrences do not share the same indices.)
 */
string longestRepeatedSubSeq(const string& str) {
    int n = static_cast<int>(str.size());
    /* dp[i][j] stores the length of the longest repeated subsequence
       for prefixes str[0..i-1] and str[0..j-1]. */
    vector<vector<int>> dp(n + 1, vector<int>(n + 1, 0));
    // Build the DP table
    for (int i = 1; i <= n; ++i) {
        for (int j = 1; j <= n; ++j) {
            if (str[i - 1] == str[j - 1] && i != j)
                dp[i][j] = 1 + dp[i - 1][j - 1];
            else
                dp[i][j] = max(dp[i][j - 1], dp[i - 1][j]);
        }
    }
    // Reconstruct the subsequence from the DP table
    string res;
    int i = n, j = n;
    while (i > 0 && j > 0) {
        if (str[i - 1] == str[j - 1] && i != j &&
            dp[i][j] == dp[i - 1][j - 1] + 1) {
            res.push_back(str[i - 1]);
            --i;
            --j;
        } else if (dp[i][j] == dp[i - 1][j]) {
            --i;
        } else {
            --j;
        }
    }
    reverse(res.begin(), res.end());
    return res;
}
