long long maxCoefficientValue(int n) {
    // Create (n+1) x (n+1) table initialized to 0
    std::vector<std::vector<long long>> C(n + 1, std::vector<long long>(n + 1, 0));
    // Build Pascal's triangle up to row n
    for (int i = 0; i <= n; ++i) {
        for (int j = 0; j <= std::min(i, n); ++j) {
            if (j == 0 || j == i) {
                C[i][j] = 1;                         // Base cases
            } else {
                C[i][j] = C[i - 1][j - 1] + C[i - 1][j];  // Pascal's rule
            }
        }
    }
    // Find the maximum value in the nth row
    long long maxValue = 0;
    for (int i = 0; i <= n; ++i) {
        maxValue = std::max(maxValue, C[n][i]);
    }
    return maxValue;
}
