// Returns the maximum profit that can be made with at most two transactions.
int maxProfit(const std::vector<int>& price)
{
    int n = static_cast<int>(price.size());
    if (n == 0) return 0;           // Edge-case: empty price list.
    std::vector<int> profit(n, 0);  // profit[i] stores the maximum profit
                                    // achievable from day i to the end
                                    // (during the first pass).
    /* ---------- First pass: scan from right to left ---------- */
    int max_price = price[n - 1];
    for (int i = n - 2; i > 0; --i)   // loop runs down to index 1 (inclusive)
    {
        if (price[i] > max_price)
            max_price = price[i];
        // Either keep previous best, or sell on day `i` at `max_price`.
        profit[i] = std::max(profit[i + 1], max_price - price[i]);
    }
    /* ---------- Second pass: scan from left to right ---------- */
    int min_price = price[0];
    for (int i = 1; i < n; ++i)
    {
        if (price[i] < min_price)
            min_price = price[i];
        // Either keep previous best, or buy at `min_price` and add
        // to the best we could make afterwards (stored in profit[i]).
        profit[i] = std::max(profit[i - 1],
                             profit[i] + (price[i] - min_price));
    }
    return profit[n - 1];
}

