            msds[i] = msds[i + 1] + arr[i];
        else
            msds[i] = arr[i];
    }
    /* Combine both arrays to find the maximum bitonic sum */
    for (int i = 0; i < n; ++i)
    {
        long long current = msis[i] + msds[i] - arr[i]; // arr[i] counted twice
