// Returns the maximum sum sub-array after removing exactly one element
int maxSumSubarrayRemovingOneEle(const std::vector<int>& arr)
{
    int n = static_cast<int>(arr.size());
    if (n == 0) return 0;            // empty array
    if (n == 1) return arr[0];       // only one element, nothing to remove
    std::vector<int> fw(n, 0);       // fw[i] -> max sub-array sum ending at i
    std::vector<int> bw(n, 0);       // bw[i] -> max sub-array sum starting at i
    /* Forward pass (Kadane’s ending at each index) */
    int cur_max = arr[0];
    int max_so_far = arr[0];
    fw[0] = arr[0];
    for (int i = 1; i < n; ++i) {
        cur_max   = std::max(arr[i], cur_max + arr[i]);
        max_so_far = std::max(max_so_far, cur_max);
        fw[i] = cur_max;
    }
    /* Backward pass (Kadane’s starting at each index) */
    cur_max = arr[n - 1];
    max_so_far = arr[n - 1];
    bw[n - 1] = arr[n - 1];
    for (int i = n - 2; i >= 0; --i) {
        cur_max   = std::max(arr[i], cur_max + arr[i]);
        max_so_far = std::max(max_so_far, cur_max);
        bw[i] = cur_max;
    }
    /* Try removing one element */
    int answer = max_so_far;                // case: no element removed
    for (int i = 1; i < n - 1; ++i) {       // remove element at i
        answer = std::max(answer, fw[i - 1] + bw[i + 1]);
    }
    return answer;
}

