// Function to get the minimum possible difference
int getMinDiff(vector<int>& arr, int n, int k)
{
    if (n == 1)                       // Only one element → difference is 0
        return 0;
    sort(arr.begin(), arr.end());     // Sort the array
    int ans   = arr[n - 1] - arr[0];  // Initial (unmodified) difference
    int small = arr[0] + k;           // Potential new smallest value
    int big   = arr[n - 1] - k;       // Potential new largest value
    if (small > big)                  // Ensure small <= big
        swap(small, big);
    // Traverse internal elements
    for (int i = 1; i < n - 1; ++i) {
        int subtract = arr[i] - k;    // Lowered value for current element
        int add      = arr[i] + k;    // Raised value for current element
        // If adjustment keeps value within [small, big] range, skip
        if (subtract >= small || add <= big)
            continue;
        // Decide whether to update `small` or `big`
        if (big - subtract <= add - small)
            small = subtract;
        else
            big = add;
    }
    return min(ans, big - small);
}

