/*
 * Recursive DP version of the given Python function.
 * X, Y : input strings
 * l, r : current indices in X and Y (0-based)
 * k    : number of pairs still to take
 * dp   : 3-D memo table initialised with -1
 */
int solve(const string &X, const string &Y,
          int l, int r, int k,
          vector<vector<vector<int>>> &dp)
{
    if (k == 0)                  // no more pairs to pick
        return 0;
    if (l < 0 || r < 0)          // ran out of characters
        return INF;
    int &memo = dp[l][r][k];
    if (memo != -1)              // already computed
        return memo;
    // XOR cost of pairing X[l] with Y[r]
    int cost = ( (X[l] - 'a') ^ (Y[r] - 'a') );
    int take   = cost + solve(X, Y, l - 1, r - 1, k - 1, dp); // take both
    int skipX  = solve(X, Y, l - 1, r,     k,     dp);        // skip X[l]
    int skipY  = solve(X, Y, l,     r - 1, k,     dp);        // skip Y[r]
    memo = min({take, skipX, skipY});
    return memo;
}

