/*
 *  MinimumCost:
 *  cost : array where cost[i] is the cost of an item of weight i+1
 *         (cost[i] == -1 means that weight i+1 is unavailable)
 *  n    : size of the cost array
 *  W    : target weight
 *
 *  Returns the minimum total cost to make exactly weight W,
 *  or -1 if it is impossible.
 */
long long MinimumCost(const vector<int>& cost, int n, int W)
{
    vector<int> val;  // cost of available items
    vector<int> wt;   // corresponding weights
    // Filter out unavailable items (cost == -1)
    for (int i = 0; i < n; ++i) {
        if (cost[i] != -1) {
            val.push_back(cost[i]);
            wt.push_back(i + 1); // weight is index + 1
        }
    }
    n = static_cast<int>(val.size());          // new number of available items
    vector<vector<long long>> dp(n + 1, vector<long long>(W + 1, 0));
    // Initialize first row (item count = 0)
    for (int j = 0; j <= W; ++j)
        dp[0][j] = INF;
    // Initialize first column (weight = 0)
    for (int i = 1; i <= n; ++i)
        dp[i][0] = 0;
    // Dynamic programming to fill the dp table
    for (int i = 1; i <= n; ++i) {
        for (int w = 1; w <= W; ++w) {
            if (wt[i - 1] > w) {
                dp[i][w] = dp[i - 1][w];  // cannot take current item
            } else {
                dp[i][w] = min(dp[i - 1][w],
                               dp[i][w - wt[i - 1]] + val[i - 1]);
            }
        }
    }
    return (dp[n][W] >= INF) ? -1 : dp[n][W];
}
