 * Computes the minimum perimeter of a rectangle that can contain `n` unit squares.
 * Mirrors the logic of the provided Python implementation.
 */
long long minPerimeter(long long n)
{
    // Floor of the square root of n
    long long l  = static_cast<long long>(std::sqrt(static_cast<long double>(n)));
    long long sq = l * l;
    // If n is a perfect square, the rectangle is l x l
    if (sq == n)
        return l * 4;
    // Otherwise, find dimensions that minimize the perimeter
    long long row       = n / l;              // Number of full rows of length l
    long long perimeter = 2 * (l + row);      // Base perimeter
    // If there's a remainder, we need an extra partial row/column → +2 to perimeter
    if (n % l != 0)
        perimeter += 2;
    return perimeter;
}

