long long minProductSubset(const vector<long long>& a)
{
    int n = static_cast<int>(a.size());
    if (n == 1) return a[0];
    long long max_neg = LLONG_MIN;   // Largest (closest to 0) negative number
    long long min_pos = LLONG_MAX;   // Smallest positive number
    int count_neg  = 0;              // Number of negative elements
    int count_zero = 0;              // Number of zeros
    long long prod = 1;              // Product of non-zero elements
    for (int i = 0; i < n; ++i)
    {
