        {
            ++count_zero;
            continue;
        }
        if (a[i] < 0)
        {
            ++count_neg;
            max_neg = max(max_neg, a[i]);
        }
        else // a[i] > 0
        {
            min_pos = min(min_pos, a[i]);
        }
        prod *= a[i];
    }
    // If all elements are zero or no negative numbers but at least one zero
    if (count_zero == n || (count_neg == 0 && count_zero > 0))
        return 0;
    // If there are no negative numbers
    if (count_neg == 0)
        return min_pos;
    // If count of negative numbers is even, divide by the largest negative
    if ((count_neg & 1) == 0)
