long long answer(int n) {
    // dp[i][j] stores the number of ways of building a length-i number
    // that ends with digit j.
    std::vector<std::vector<long long>> dp(n + 1, std::vector<long long>(10, 0));
    if (n == 1)                      // Base case (single-digit numbers)
        return 10;
    for (int j = 0; j < 10; ++j)     // All one-digit numbers are valid
        dp[1][j] = 1;
    for (int i = 2; i <= n; ++i) {   // Build up to length n
        for (int j = 0; j < 10; ++j) {
            if (j == 0)
                dp[i][j] = dp[i - 1][j + 1];               // Can only come from 1
            else if (j == 9)
                dp[i][j] = dp[i - 1][j - 1];               // Can only come from 8
            else
                dp[i][j] = dp[i - 1][j - 1] + dp[i - 1][j + 1]; // From j-1 or j+1
        }
    }
    long long sum = 0;               // Sum for leading digit ≠ 0
    for (int j = 1; j < 10; ++j)
        sum += dp[n][j];
    return sum;
}

