/*
 * Checks whether there exists a pair of distinct elements in `arr`
 * whose product equals `x`.
 *
 * @param arr : input array
 * @param n   : size of the array
 * @param x   : target product
 * @return    : true if such a pair exists, otherwise false
 */
bool isProduct(const vector<long long>& arr, int n, long long x) {
    if (n < 2) return false;
    unordered_set<long long> seen;
    for (int i = 0; i < n; ++i) {
        long long val = arr[i];
        // Handle zero separately
        if (val == 0) {
            if (x == 0) return true;   // 0 * 0 == 0
            continue;                  // otherwise skip
        }
        // Check if current value can pair with a previously seen value
        if (x % val == 0) {
            long long needed = x / val;
            if (seen.count(needed)) return true;
            seen.insert(val);
        }
    }
    return false;
}
