// Calculates the maximum average along a path from the top-left corner to the
// bottom-right corner of an N×N grid, moving only right or down.
double maxAverageOfPath(const std::vector<std::vector<int>>& cost, int N) {
    // dp[i][j] stores the maximum total cost achievable to reach cell (i, j)
    std::vector<std::vector<long long>> dp(N, std::vector<long long>(N, 0));
    dp[0][0] = cost[0][0];
    // Fill the first column
    for (int i = 1; i < N; ++i)
        dp[i][0] = dp[i - 1][0] + cost[i][0];
    // Fill the first row
    for (int j = 1; j < N; ++j)
        dp[0][j] = dp[0][j - 1] + cost[0][j];
    // Fill the remaining cells
    for (int i = 1; i < N; ++i) {
        for (int j = 1; j < N; ++j) {
            dp[i][j] = std::max(dp[i - 1][j], dp[i][j - 1]) + cost[i][j];
        }
    }
    // The path length is always (2 * N - 1) for an N×N grid.
    return static_cast<double>(dp[N - 1][N - 1]) / (2 * N - 1);
}

