// Rearranges the array so that elements at even indices are non-negative
// and elements at odd indices are negative (same logic as the Python code).
void rearrange(std::vector<int>& a)
{
    const int size = static_cast<int>(a.size());
    int positive = 0;  // even indices (0, 2, 4, …)
    int negative = 1;  // odd  indices (1, 3, 5, …)
    while (true)
    {
        while (positive < size && a[positive] >= 0)
            positive += 2;
        while (negative < size && a[negative] <= 0)
            negative += 2;
        if (positive < size && negative < size)
            std::swap(a[positive], a[negative]);
        else
            break;
    }
}

