/*
 * Equivalent of the given Python function.
 * a : array of integers
 * n : size of the array
 * k : target value used in the second pass
 *
 * Returns the computed answer exactly as the Python version.
 */
long long find_maximum(const vector<long long>& a, int n, long long k)
{
    unordered_map<long long, long long> b;        // corresponds to Python dict `b`
    /* First pass: store the minimal distance (to either array end) for every value */
    for (int i = 0; i < n; ++i) {
        long long x = a[i];
        long long d = min<long long>(i + 1, n - i);   // min(1 + i, n - i)
        auto it = b.find(x);
        if (it == b.end())
            b[x] = d;
        else
            b[x] = min(b[x], d);
    }
    long long ans = LLONG_MAX;   // same as Python's `sys.maxsize`
    /* Second pass: try every a[i] as candidate together with (k - a[i]) */
    for (int i = 0; i < n; ++i) {
        long long x = a[i];
        if (x != k - x && b.count(k - x)) {
            ans = min(ans, max(b[x], b[k - x]));
        }
    }
    return ans;
}

