// Inserts 'key' into sorted array 'arr' of current size 'n' if capacity allows.
// Returns the new size of the array after insertion.
int insertSorted(int arr[], int n, int key, int capacity) {
    // If there is no room to insert, return the original size.
    if (n >= capacity)
        return n;
    int i = n - 1;
    // Shift elements greater than key to one position ahead.
    while (i >= 0 && arr[i] > key) {
        arr[i + 1] = arr[i];
        --i;
    }
    // Place key at its correct position.
    arr[i + 1] = key;
    // New size is old size + 1.
    return n + 1;
}

