 * Translated version of the given Python function.
 * It first transforms every element in `arr` with the
 * quadratic expression  A*x*x + B*x + C,
 * then finds the maximum element and its position,
 * and finally re-orders the array following the same rules
 * as the original Python code.
 */
void sortArray(vector<long long>& arr,
               int n,
               long long A,
               long long B,
               long long C)
{
    /* 1) Apply the quadratic transformation */
    for (int i = 0; i < n; ++i)
        arr[i] = A * arr[i] * arr[i] + B * arr[i] + C;
    /* 2) Locate the maximum value and its index */
    long long maximum = std::numeric_limits<long long>::min();
    int        index  = std::numeric_limits<int>::min();
    for (int i = 0; i < n; ++i)
    {
        if (maximum < arr[i])
        {
            maximum = arr[i];
            index   = i;
        }
    }
    /* 3) Build the new array according to the original logic */
    vector<long long> new_arr(n, 0);
    int i = 0, j = n - 1, k = 0;
    while (i < index && j > index)
    {
        if (arr[i] < arr[j])
            new_arr[k++] = arr[i++];
        else
            new_arr[k++] = arr[j--];
    }
    while (i < index)
        new_arr[k++] = arr[i++];
    while (j > index)
    {
        new_arr[k++]     = arr[j--];
        new_arr[n - 1]   = maximum;     // same placement as in Python
    }
