// Binary GCD (Stein's algorithm)
long long gcd(long long a, long long b)
{
    if (a == 0) return b;
    if (b == 0) return a;
    int k = 0;
    // Remove common factors of 2 from both numbers
    while (((a | b) & 1) == 0) {
        a >>= 1;
        b >>= 1;
        ++k;
    }
    // Make 'a' odd
    while ((a & 1) == 0) {
        a >>= 1;
    }
    while (b != 0) {
        // Make 'b' odd
        while ((b & 1) == 0) {
            b >>= 1;
        }
        // Ensure a <= b
        if (a > b) {
            std::swap(a, b);
        }
        // Now b >= a, so replace b by b - a (which is even)
        b -= a;
    }
    // Restore common factors of 2
    return a << k;
}

