// Returns the required sum for the array `arr` of size `n`
long long sumoflength(const vector<int>& arr, int n)
{
    unordered_set<int> s;   // stores the current window’s distinct elements
    int j = 0;              // right-end of the sliding window
    long long ans = 0;      // final answer
    for (int i = 0; i < n; ++i)
    {
        // Extend the window to the right while elements remain distinct
        while (j < n && s.find(arr[j]) == s.end())
        {
            s.insert(arr[j]);
            ++j;
        }
        /*  Number of subarrays that start at index `i`
            and end anywhere in the current window is:
                  len = j - i
            Their contribution to the answer is
                  len * (len + 1) / 2
        */
        long long len = j - i;
        ans += (len * (len + 1)) / 2;
        // Shrink the window from the left for the next iteration
        s.erase(arr[i]);
    }
    return ans;
}

