                    dp[i][j] = (a[j] == b[i]) ? 1 : 0;
                } else {
                    dp[i][j] = dp[i][j - 1] + ((a[j] == b[i]) ? 1 : 0);
                }
            } else {
                if (a[j] == b[i]) {
                    dp[i][j] = dp[i][j - 1] + dp[i - 1][j - 1];
                } else {
                    dp[i][j] = dp[i][j - 1];
                }
            }
        }
    }
    return dp[m - 1][n - 1];
}

