// Returns true (1) if n is a multiple of 3, false (0) otherwise.
bool isMultipleOf3(long long n)
{
    if (n < 0)
        n = -n;                     // make n non-negative
    if (n == 0)
        return true;                // 0 is divisible by 3
    if (n == 1)
        return false;               // 1 is not divisible by 3
    int odd_count  = 0;
    int even_count = 0;
    // Process bits two at a time
    while (n)
    {
        if (n & 1)  odd_count++;    // LSB is an odd-positioned bit
        if (n & 2)  even_count++;   // next bit is an even-positioned bit
        n >>= 2;                    // move to the next pair of bits
    }
    // Recursively check the difference of counts
    return isMultipleOf3(std::abs(odd_count - even_count));
}
